-- =============================================================================
-- content/hand_reading_workbook_2026_1.sql
-- Appendix C Рђћ Hand Reading Workbook (50 practice hands), from TGI Manual v1.
--
-- Loaded as a SELF-CHECK FLASHCARD deck under Ch 20 (Professional Hand Reading
-- Drills): front = the hand scenario + question, back = the manual's answer.
-- The manual frames this as a self-check workbook ("cover the answer key and
-- attempt every hand before checking"), so it is study content, not a graded
-- exam.
--
-- NOTE (data quality): several answer-key entries in the source contain the
-- author's working-out with self-corrections (e.g. "A wins: ... B wins."). The
-- text is reproduced VERBATIM from the manual and NOT machine-normalized Рђћ the
-- institute should review/clean the answer key. That is also why this loads as
-- a self-check deck rather than an auto-graded quiz (no reliable machine key).
--
-- Idempotent (deterministic ids). \ir-included by seed.sql.
-- =============================================================================

\set course_id '''00000000-0000-0000-0000-000000000010'''

insert into flashcards (id, chapter_id, front, back, sequence, is_active)
select v.id::uuid, ch.id, v.front, v.back, v.seq, true
from (values
  ('00000000-0000-0000-0000-0000000c0001', '[Tier 1 ┬и Hold''em] Hold''em Рђћ Board KРЎа KРЎд 7РЎБ 4РЎЦ 2РЎа; A holds KРЎБ QРЎа; B holds AРЎЦ AРЎБ  Who wins?', 'A wins: trip Kings beats two pair (Aces & Kings... B has KK+AA two pair). A: KKK; B: AA KK. Trips beat two pair Рђћ A wins.', 1),
  ('00000000-0000-0000-0000-0000000c0002', '[Tier 1 ┬и Hold''em] Hold''em Рђћ Board 9РЎа 8РЎа 7РЎа 2РЎд 2РЎБ; A holds AРЎа 3РЎа; B holds 9РЎЦ 9РЎд  Who wins?', 'A wins: Ace-high flush beats B''s set of nines.', 2),
  ('00000000-0000-0000-0000-0000000c0003', '[Tier 1 ┬и Hold''em] Hold''em Рђћ Board QРЎд JРЎБ 10РЎЦ 4РЎа 2РЎБ; A holds AРЎа KРЎд; B holds QРЎБ QРЎа  Who wins?', 'A wins: Broadway straight (A-K-Q-J-10) beats set of Queens.', 3),
  ('00000000-0000-0000-0000-0000000c0004', '[Tier 1 ┬и Hold''em] Hold''em Рђћ Board 5РЎБ 5РЎд 5РЎа KРЎЦ 2РЎБ; A holds KРЎБ QРЎа; B holds 6РЎа 6РЎЦ  Who wins?', 'A wins: fives full of Kings beats fives full of sixes? A: 555KK; B: 555 66 Рєњ fives full of Kings beats fives full of sixes Рђћ A wins.', 4),
  ('00000000-0000-0000-0000-0000000c0005', '[Tier 1 ┬и Hold''em] Hold''em Рђћ Board AРЎд KРЎБ QРЎЦ JРЎа 9РЎа; A holds 10РЎа 2РЎБ; B holds AРЎБ AРЎа  Who wins?', 'A wins: A-K-Q-J-10 straight beats trip Aces.', 5),
  ('00000000-0000-0000-0000-0000000c0006', '[Tier 1 ┬и Hold''em] Hold''em Рђћ Board 8РЎЦ 8РЎд 4РЎБ 4РЎа KРЎЦ; A holds AРЎа 8РЎа; B holds KРЎБ KРЎд  Who wins?', 'A wins: eights full of fours? A: 888 44 Рєњ eights full of fours; B: KKK 88? B has KKK + 88 Рєњ Kings full of eights. B wins.', 6),
  ('00000000-0000-0000-0000-0000000c0007', '[Tier 1 ┬и Hold''em] Hold''em Рђћ Board JРЎа 10РЎа 9РЎа 2РЎд 3РЎБ; A holds QРЎа 8РЎа; B holds AРЎа 4РЎБ  Who wins?', 'A wins: Queen-high straight flush (Q-J-10-9-8 all spades) beats B''s nut spade flush.', 7),
  ('00000000-0000-0000-0000-0000000c0008', '[Tier 1 ┬и Hold''em] Hold''em Рђћ Board 7РЎБ 7РЎд 7РЎа KРЎЦ KРЎа; A holds 7РЎЦ 2РЎБ; B holds KРЎБ QРЎа  Who wins?', 'A wins: quad sevens beats B''s Kings full.', 8),
  ('00000000-0000-0000-0000-0000000c0009', '[Tier 1 ┬и Hold''em] Hold''em Рђћ Board AРЎЦ KРЎЦ 5РЎд 5РЎБ 9РЎа; A holds AРЎа KРЎБ; B holds 9РЎЦ 9РЎд  Who wins?', 'A wins: Aces & Kings two pair? A: AA KK 9; B: 999 55. Set of nines? B has 99+55 Рєњ nines full? No: 9-9-9-5-5 = nines full of fives. B wins.', 9),
  ('00000000-0000-0000-0000-0000000c0010', '[Tier 1 ┬и Hold''em] Hold''em Рђћ Board 2РЎБ 3РЎБ 4РЎБ 5РЎБ 9РЎа; A holds 6РЎБ KРЎа; B holds AРЎБ 10РЎа  Who wins?', 'B wins: Ace-high club flush beats A''s six-high straight flush? A has 2-3-4-5-6 all clubs = straight flush. A wins.', 10),
  ('00000000-0000-0000-0000-0000000c0011', '[Tier 1 ┬и Hold''em] Hold''em Рђћ Board KРЎа QРЎд 7РЎЦ 7РЎБ KРЎд; A holds KРЎБ 5РЎа; B holds QРЎБ QРЎа  Who wins?', 'A wins: Kings full of sevens beats Queens full of sevens? B: QQQ 77 Рєњ Queens full of sevens; A: KKK 77 Рєњ Kings full. A wins.', 11),
  ('00000000-0000-0000-0000-0000000c0012', '[Tier 1 ┬и Hold''em] Hold''em Рђћ Board 10РЎд 10РЎБ 9РЎа 9РЎЦ 2РЎБ; A holds AРЎа 10РЎа; B holds 9РЎБ KРЎа  Who wins?', 'A wins: tens full of nines beats nines full of tens.', 12),
  ('00000000-0000-0000-0000-0000000c0013', '[Tier 1 ┬и Hold''em] Hold''em Рђћ Board AРЎа 7РЎд 7РЎа 7РЎБ 2РЎЦ; A holds AРЎБ KРЎа; B holds 7РЎЦ 4РЎБ  Who wins?', 'B wins: quad sevens beats A''s sevens full of Aces.', 13),
  ('00000000-0000-0000-0000-0000000c0014', '[Tier 1 ┬и Hold''em] Hold''em Рђћ Board JРЎЦ JРЎБ JРЎа 4РЎд 4РЎБ; A holds JРЎд 2РЎа; B holds AРЎЦ AРЎа  Who wins?', 'A wins: quad Jacks beats B''s Aces full of Jacks.', 14),
  ('00000000-0000-0000-0000-0000000c0015', '[Tier 1 ┬и Hold''em] Hold''em Рђћ Board 6РЎа 7РЎа 8РЎа 9РЎа 2РЎЦ; A holds 10РЎа 3РЎБ; B holds 5РЎа 4РЎБ  Who wins?', 'A wins: ten-high straight flush beats B''s nine-high straight flush.', 15),
  ('00000000-0000-0000-0000-0000000c0016', '[Tier 1 ┬и Hold''em] Hold''em Рђћ Board KРЎБ 7РЎд 2РЎа 2РЎБ 2РЎЦ; A holds KРЎа QРЎа; B holds AРЎа 7РЎБ  Who wins?', 'A wins: Kings full of deuces? A: 222 KK; B: 222 77. Both trips of deuces, A''s pair higher Рєњ A wins.', 16),
  ('00000000-0000-0000-0000-0000000c0017', '[Tier 1 ┬и Hold''em] Hold''em Рђћ Board AРЎа AРЎд KРЎЦ KРЎБ QРЎа; A holds AРЎБ 2РЎа; B holds KРЎа JРЎБ  Who wins?', 'A wins: trip Aces full of Kings beats B''s Kings full of Aces.', 17),
  ('00000000-0000-0000-0000-0000000c0018', '[Tier 1 ┬и Hold''em] Hold''em Рђћ Board 3РЎЦ 3РЎБ 6РЎд 6РЎБ 6РЎа; A holds 3РЎа KРЎа; B holds 6РЎЦ AРЎБ  Who wins?', 'B wins: quad sixes beats A''s sixes full of threes.', 18),
  ('00000000-0000-0000-0000-0000000c0019', '[Tier 2 ┬и Omaha] Omaha Рђћ Board AРЎа KРЎа QРЎа JРЎа 2РЎЦ; Player holds 10РЎа 9РЎа 4РЎБ 3РЎд  Best hand? Does a flush play?', 'Must use exactly two hole cards. Player has only one spade pair option: 10РЎа 9РЎа + three board spades = K-Q-J-10-9 spade flush? Uses 10РЎа 9РЎа + AРЎа KРЎа QРЎа Рєњ A-K-Q-10-9 spade flush. Yes, flush plays.', 19),
  ('00000000-0000-0000-0000-0000000c0020', '[Tier 2 ┬и Omaha] Omaha Рђћ Board 8РЎЦ 8РЎд 8РЎа KРЎБ 2РЎа; Player holds 8РЎБ AРЎа KРЎа 5РЎд  Best hand?', 'Use 8РЎБ + one more: only one 8 in hand. Use 8РЎБ AРЎа Рєњ with board 888 = quad eights (8РЎБ + 8-8-8 board) but must use exactly two hole + three board. Two hole: 8РЎБ KРЎа + 8-8-K board = eights full of Kings? Best: 8РЎБ + AРЎа with 8-8-8 Рєњ not legal (only one board 8 usable beyond). Quads: 8РЎБ (hole) + 8РЎа 8РЎд 8РЎЦ (board=3) + need 2 hole Рєњ 8РЎБ AРЎа + 8-8-8 = quad eights, Ace kicker.', 20),
  ('00000000-0000-0000-0000-0000000c0021', '[Tier 2 ┬и Omaha] Omaha Рђћ Board 9РЎд 9РЎБ 4РЎа 4РЎЦ KРЎа; Player holds 9РЎа 9РЎЦ AРЎБ 2РЎд  Best hand?', 'Two hole 9РЎа 9РЎЦ + board 9-9-4? Only two board nines? Board has 9РЎд 9РЎБ. Use 9РЎа 9РЎЦ + 9РЎд? That''s three hole? No Рђћ two hole 9s + board 9 = trips plus... Use 9РЎа 9РЎЦ (hole) + 9РЎд 4 4 (board) = nines full of fours.', 21),
  ('00000000-0000-0000-0000-0000000c0022', '[Tier 2 ┬и Omaha] Omaha Рђћ Board AРЎа 5РЎд 7РЎБ 9РЎЦ 10РЎа; Player holds KРЎа QРЎа JРЎБ 2РЎа  Does the player have a flush?', 'No. Only two board spades (AРЎа 10РЎа). Two hole spades (KРЎа QРЎа or 2РЎа) + two board spades = only four spades. No flush.', 22),
  ('00000000-0000-0000-0000-0000000c0023', '[Tier 2 ┬и Omaha] Omaha Рђћ Board 2РЎБ 3РЎБ 4РЎБ 5РЎд 6РЎЦ; Player holds AРЎБ KРЎБ 7РЎа 8РЎд  Best hand?', 'Straight: use 7РЎа... must use two hole. 7 from hole + 3-4-5-6? Only one 7 in hole (7РЎа) + need second hole: AРЎБ with 2-3-4-5 = A-2-3-4-5 wheel using AРЎБ + one more? Use AРЎБ + 7РЎа? Not connected. Best legal straight: use AРЎБ and a club? Flush needs 3 board clubs (2РЎБ 3РЎБ 4РЎБ) + AРЎБ KРЎБ = A-K-4-3-2 club flush. Flush plays.', 23),
  ('00000000-0000-0000-0000-0000000c0024', '[Tier 2 ┬и Omaha] Omaha Рђћ Board KРЎд KРЎБ 7РЎа 7РЎЦ 2РЎБ; Player holds KРЎа AРЎд QРЎБ JРЎа  Best hand?', 'Use KРЎа + one hole + board K-K-7 = trip Kings? Two hole: KРЎа AРЎд + K-K-7 = Kings full of sevens.', 24),
  ('00000000-0000-0000-0000-0000000c0025', '[Tier 2 ┬и Omaha] Omaha Рђћ Board 10РЎЦ JРЎЦ QРЎЦ 2РЎБ 3РЎд; Player holds AРЎЦ KРЎЦ 4РЎа 5РЎа  Best hand?', 'AРЎЦ KРЎЦ (two hole) + 10РЎЦ JРЎЦ QРЎЦ (board) = A-K-Q-J-10 royal flush in hearts.', 25),
  ('00000000-0000-0000-0000-0000000c0026', '[Tier 2 ┬и Omaha] Omaha Рђћ Board 6РЎа 6РЎд 6РЎБ KРЎЦ KРЎа; Player holds 6РЎЦ AРЎа QРЎБ JРЎд  Best hand?', '6РЎЦ (hole) + need two hole: 6РЎЦ AРЎа + 6-6-K = sixes... use 6РЎЦ + AРЎа with board 6-6-K Рєњ quad sixes (6РЎЦ + 6РЎа 6РЎд 6РЎБ) needs only one hole 6 + ... exactly two hole: 6РЎЦ AРЎа + 6РЎд 6РЎБ K = quad sixes, Ace kicker.', 26),
  ('00000000-0000-0000-0000-0000000c0027', '[Tier 2 ┬и Omaha] Omaha Рђћ Board AРЎд AРЎБ KРЎа KРЎБ 5РЎЦ; Player holds AРЎа AРЎЦ 2РЎБ 3РЎд  Best hand?', 'AРЎа AРЎЦ (hole) + AРЎд ... only board has AРЎд AРЎБ. Two hole Aces + one board Ace = quad Aces? Use AРЎа AРЎЦ + AРЎд AРЎБ K = quad Aces, King kicker.', 27),
  ('00000000-0000-0000-0000-0000000c0028', '[Tier 2 ┬и Omaha] Omaha Рђћ Board QРЎБ JРЎа 9РЎд 8РЎЦ 2РЎБ; Player holds 10РЎа 10РЎЦ AРЎа KРЎБ  Best hand?', '10РЎа (hole) + need second hole for straight: use 10РЎЦ + Q J 9 8? 10 fills Q-J-10-9-8. Use 10РЎа 10РЎЦ? Only need one 10. Use 10РЎа + KРЎБ? Not straight. Use 10 + any: 10РЎа AРЎа doesn''t help. Best straight uses 10 + one card making Q-J-10-9-8: that requires only the single 10 from hole + a second hole card in the run. No second hole card connects. So pair of tens only? Actually Q-J-_-9-8 needs a 10; player has 10s but must pick a 2nd hole card from {A,K} Рєњ no straight. Best = pair of tens.', 28),
  ('00000000-0000-0000-0000-0000000c0029', '[Tier 2 ┬и Omaha] Omaha Рђћ Board 7РЎБ 8РЎБ 9РЎБ 2РЎд 2РЎа; Player holds 10РЎБ JРЎБ AРЎа KРЎЦ  Best hand?', '10РЎБ JРЎБ (hole) + 7РЎБ 8РЎБ 9РЎБ (board) = J-10-9-8-7 straight flush in clubs.', 29),
  ('00000000-0000-0000-0000-0000000c0030', '[Tier 2 ┬и Omaha] Omaha Рђћ Board AРЎа KРЎЦ QРЎд 5РЎБ 5РЎа; Player holds 5РЎЦ 5РЎд AРЎБ KРЎБ  Best hand?', '5РЎЦ 5РЎд (hole) + 5РЎБ 5РЎа (board) = quad fives, Ace kicker.', 30),
  ('00000000-0000-0000-0000-0000000c0031', '[Tier 2 ┬и Omaha] Omaha Рђћ Board 3РЎа 4РЎа 5РЎа 6РЎд 7РЎБ; Player holds 2РЎа AРЎа KРЎд QРЎБ  Flush or straight?', '2РЎа AРЎа (hole) + 3РЎа 4РЎа 5РЎа (board) = A-5-4-3-2 spade flush. Straight 7-6-5-4-3 needs two hole in run Рђћ player lacks them. Flush plays.', 31),
  ('00000000-0000-0000-0000-0000000c0032', '[Tier 2 ┬и Omaha] Omaha Рђћ Board 10РЎд 10РЎБ JРЎЦ JРЎа AРЎБ; Player holds JРЎБ JРЎд 2РЎа 3РЎЦ  Best hand?', 'JРЎБ JРЎд (hole) + JРЎЦ JРЎа (board) = quad Jacks, Ace kicker.', 32),
  ('00000000-0000-0000-0000-0000000c0033', '[Tier 2 ┬и Omaha] Omaha Рђћ Board KРЎБ QРЎБ JРЎБ 10РЎа 9РЎа; Player holds AРЎБ 10РЎБ 2РЎд 3РЎЦ  Best hand?', 'AРЎБ 10РЎБ (hole) + KРЎБ QРЎБ JРЎБ (board) = A-K-Q-J-10 royal flush in clubs.', 33),
  ('00000000-0000-0000-0000-0000000c0034', '[Tier 2 ┬и Omaha] Omaha Рђћ Board 4РЎЦ 4РЎд 9РЎБ 9РЎа 9РЎЦ; Player holds 9РЎд AРЎа KРЎБ QРЎд  Best hand?', '9РЎд AРЎа (hole) + 9-9-9 board? Two hole + three board: 9РЎд + one hole + 9РЎа 9РЎЦ 4 Рєњ quad nines needs 9РЎд + 9РЎБ 9РЎа 9РЎЦ (that''s one hole + three board = 4 cards, only one hole) illegal. Legal: 9РЎд AРЎа + 9РЎБ 9РЎа 9РЎЦ? that''s two hole + three board = 9РЎд(hole) AРЎа(hole) + 9РЎБ 9РЎа 9РЎЦ (board) = quad nines, Ace kicker.', 34),
  ('00000000-0000-0000-0000-0000000c0035', '[Tier 3 ┬и Big O, Side Pots & Odd Chips] Big O Рђћ Board AРЎд 2РЎБ 7РЎЦ 9РЎа KРЎБ; Player holds 3РЎд 4РЎа 5РЎБ 8РЎЦ JРЎа  Does a low qualify? Best low?', 'Yes. Use 3РЎд 4РЎа (hole) + A 2 7 (board) = A-2-3-4-7 Рєњ seven-low. Qualifies (eight-or-better).', 35),
  ('00000000-0000-0000-0000-0000000c0036', '[Tier 3 ┬и Big O, Side Pots & Odd Chips] Big O Рђћ Board 5РЎа 6РЎд 7РЎБ 8РЎЦ KРЎа; Player holds AРЎБ 2РЎа 9РЎЦ 10РЎд JРЎБ  Best high and qualifying low?', 'High: 9-10 + 5-6-7-8? Use 9РЎЦ 10РЎд + 6 7 8 = 10-9-8-7-6 straight. Low: AРЎБ 2РЎа + 5 6 7 = A-2-5-6-7 Рєњ seven-low qualifies.', 36),
  ('00000000-0000-0000-0000-0000000c0037', '[Tier 3 ┬и Big O, Side Pots & Odd Chips] Big O Рђћ Board 2РЎд 3РЎБ 4РЎЦ JРЎа QРЎБ; Player holds AРЎа 5РЎБ 6РЎд KРЎЦ KРЎБ  Best low?', 'AРЎа 5РЎБ (hole) + 2 3 4 (board) = A-2-3-4-5 = wheel (five-low), the best possible low.', 37),
  ('00000000-0000-0000-0000-0000000c0038', '[Tier 3 ┬и Big O, Side Pots & Odd Chips] Big O Рђћ Board 8РЎа 9РЎа 10РЎа 2РЎБ 3РЎд; Player holds AРЎа 4РЎа 5РЎд 6РЎЦ 7РЎБ  High and low?', 'High: AРЎа 4РЎа + 8РЎа 9РЎа 10РЎа = A-10-9-8-4 spade flush. Low: 4 5 + ... use two hole low + 8/9/10? board lows are only 2,3. Low needs three board cards eight-or-lower: only 2,3 qualify Рєњ no qualifying low. High scoops.', 38),
  ('00000000-0000-0000-0000-0000000c0039', '[Tier 3 ┬и Big O, Side Pots & Odd Chips] Big O Рђћ Board AРЎБ 4РЎд 5РЎБ 6РЎЦ 8РЎа; Player A holds 2РЎа 3РЎа KРЎЦ QРЎд JРЎБ; Player B holds 2РЎд 7РЎБ 9РЎа 10РЎЦ KРЎБ  Who has the better low?', 'A: 2РЎа 3РЎа + A 4 5 = A-2-3-4-5 wheel (five-low). B: 2РЎд 7РЎБ + A 4 5 = A-2-4-5-7 seven-low. A wins low (wheel beats seven-low).', 39),
  ('00000000-0000-0000-0000-0000000c0040', '[Tier 3 ┬и Big O, Side Pots & Odd Chips] Side Pots Рђћ A all-in $50; B all-in $150; C all-in $400  Build the pots.', 'Main: 50├Ќ3 = $150 (A,B,C). Side 1: 100├Ќ2 = $200 (B,C). C''s extra $250 returned. Total wagered in pots: $350 + $250 returned.', 40),
  ('00000000-0000-0000-0000-0000000c0041', '[Tier 3 ┬и Big O, Side Pots & Odd Chips] Side Pots Рђћ A all-in $80; B all-in $80; C bets $200 (covers)  Build the pots.', 'Main: 80├Ќ3 = $240 (A,B,C). C''s extra $120 returned (no opponent). Side pot: none.', 41),
  ('00000000-0000-0000-0000-0000000c0042', '[Tier 3 ┬и Big O, Side Pots & Odd Chips] Side Pots Рђћ A all-in $100; B all-in $250; C all-in $250  Build the pots.', 'Main: 100├Ќ3 = $300 (A,B,C). Side 1: 150├Ќ2 = $300 (B,C). No chips returned.', 42),
  ('00000000-0000-0000-0000-0000000c0043', '[Tier 3 ┬и Big O, Side Pots & Odd Chips] Side Pots Рђћ A $500; B all-in $120; C all-in $300; D folds preflop having posted $20 BB  Build the pots including the dead blind.', 'Dead $20 goes to main. Main: 120├Ќ3 +20 = $380 (A,B,C). Side 1: (300-120)├Ќ2 = $360 (A,C). Side 2: A''s extra $200 returned.', 43),
  ('00000000-0000-0000-0000-0000000c0044', '[Tier 3 ┬и Big O, Side Pots & Odd Chips] Odd Chips Рђћ Split pot $325 between high (A) and low (B); chips are $1  Divide and place the odd chip.', '$325 / 2 = $162.50. High receives the odd chip: A $163, B $162. Verify: 163+162 = 325.', 44),
  ('00000000-0000-0000-0000-0000000c0045', '[Tier 3 ┬и Big O, Side Pots & Odd Chips] Odd Chips Рђћ Quartered low: B and C tie for low half of a $400 pot; A wins high  Distribute.', 'High half $200 to A. Low half $200 split B/C = $100 each. If indivisible, odd chip to the high-side or first seat left of button per house rule.', 45),
  ('00000000-0000-0000-0000-0000000c0046', '[Tier 3 ┬и Big O, Side Pots & Odd Chips] Odd Chips Рђћ Three-way high tie for a $301 pot, $1 chips  Distribute.', '$301 / 3 = $100 remainder 1. Each gets $100; odd chip to the first eligible seat left of the button.', 46),
  ('00000000-0000-0000-0000-0000000c0047', '[Tier 3 ┬и Big O, Side Pots & Odd Chips] Big O Рђћ Board AРЎЦ 2РЎЦ 3РЎЦ 4РЎЦ 5РЎЦ; Player A holds 6РЎЦ 7РЎа KРЎБ QРЎд JРЎа; Player B holds AРЎа 2РЎа 8РЎБ 9РЎд 10РЎЦ  High and low results?', 'High: A plays 6РЎЦ + one heart? Two hole + three board hearts: 6РЎЦ needs a 2nd heart hole Рђћ none Рєњ no flush for A. B: AРЎа 2РЎа + 3РЎЦ 4РЎЦ 5РЎЦ? not a flush (mixed). Board is a 5-high straight flush in hearts but each player must use exactly two hole cards, so the board straight flush does NOT play by itself. Read carefully per two-card rule.', 47),
  ('00000000-0000-0000-0000-0000000c0048', '[Tier 3 ┬и Big O, Side Pots & Odd Chips] Big O Рђћ Board 7РЎБ 8РЎд 9РЎа 2РЎЦ 3РЎБ; Player holds AРЎа 4РЎБ 5РЎд 6РЎЦ 10РЎБ  Best high and low?', 'High: 5РЎд 6РЎЦ + 7 8 9 = 9-8-7-6-5 straight. Low: AРЎа 4РЎБ + 7 2 3 = A-2-3-4-7 seven-low qualifies.', 48),
  ('00000000-0000-0000-0000-0000000c0049', '[Tier 3 ┬и Big O, Side Pots & Odd Chips] Side Pots Рђћ A all-in $30; B all-in $30; C all-in $30  Build the pots.', 'Single main pot: 30├Ќ3 = $90 (A,B,C). No side pots; equal all-ins.', 49),
  ('00000000-0000-0000-0000-0000000c0050', '[Tier 3 ┬и Big O, Side Pots & Odd Chips] Odd Chips Рђћ Scoop check: Player A has the nut high and the nut low in a $500 pot  Distribute.', 'A scoops Рђћ receives the entire $500 (best high and best qualifying low). No split.', 50)
) as v(id, front, back, seq)
cross join (select id from chapters where number = 20 and course_id = :course_id) ch
on conflict (id) do update
  set front = excluded.front, back = excluded.back, sequence = excluded.sequence, chapter_id = excluded.chapter_id;
